/* Base Resets */
    body {
      margin: 0;
      font-family: 'DM Sans', -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
      background-color: var(--bg-body);
      color: var(--text);
      overflow-x: hidden;
      padding-top: var(--header-h); 
    }
    @media (max-width: 991px) { body { padding-top: 64px; } }

    a { text-decoration: none; color: var(--primary); transition: color var(--t); }
    a:hover { color: var(--primary-2); }
    p { line-height: 1.7; color: var(--text-s); font-size: 0.95rem; }

    .font-syne { font-family: 'Syne', sans-serif; }

    /* ========================================================================== */
    /* COMPONENTS & TYPOGRAPHY                                                    */
    /* ========================================================================== */
    .section-title {
      position: relative; padding-bottom: .75rem; margin-bottom: 2rem;
      font-weight: 800; color: var(--primary-d); font-family: 'Syne', sans-serif;
      font-size: clamp(1.6rem, 4vw, 2.2rem);
    }
    .section-title::after {
      content: ''; position: absolute; bottom: 0; left: 0;
      width: 60px; height: 4px; border-radius: 2px;
      background: linear-gradient(90deg, var(--primary), var(--gold));
    }
    .section-title.center::after { left: 50%; transform: translateX(-50%); }

    .btn-outline-custom {
      display: inline-flex; align-items: center; justify-content: center; gap: 8px; 
      background: #fff; color: var(--primary); font-weight: 700; font-size: .9rem; 
      padding: 12px 28px; border-radius: 50px; border: 1.5px solid var(--bdr); 
      transition: all var(--t); box-shadow: var(--sh-xs);
    }
    .btn-outline-custom:hover {
      border-color: var(--primary); color: var(--primary); transform: translateY(-2px); box-shadow: var(--sh-sm);
    }

    /* ========================================================================== */
    /* HERO SECTION                                                               */
    /* ========================================================================== */
    .hero-banner {
      position: relative; overflow: hidden;
      background: linear-gradient(135deg, var(--digital-blue-950) 0%, var(--digital-blue-900) 50%, var(--digital-blue-800) 100%);
      padding: 80px 0 100px; text-align: center;
    }
    .hero-banner::before {
      content: ''; position: absolute; inset: 0;
      background-image: 
        radial-gradient(circle at 15% 50%, rgba(51, 133, 255, 0.2), transparent 30%),
        radial-gradient(circle at 85% 30%, rgba(51, 133, 255, 0.2), transparent 30%);
      z-index: 1; pointer-events: none;
    }
    .hero-ring {
      position: absolute; border-radius: 50%; border: 1px solid rgba(255,255,255,.05);
      pointer-events: none; z-index: 1;
    }
    .hero-ring-1 { width: 600px; height: 600px; top: -200px; left: -150px; border-color: rgba(51, 133, 255, 0.15); }
    .hero-ring-2 { width: 400px; height: 400px; bottom: -100px; right: -50px; border-color: rgba(255,255,255,.05); }

    .hero-content { position: relative; z-index: 3; max-width: 800px; margin: 0 auto; }
    .hero-breadcrumb {
      display: inline-flex; align-items: center; gap: 8px;
      color: var(--gold); font-size: .75rem; font-weight: 800; text-transform: uppercase; letter-spacing: 0.08em;
      background: rgba(51, 133, 255, 0.15); border: 1px solid rgba(51, 133, 255, 0.3);
      border-radius: 50px; padding: 6px 16px; margin-bottom: 24px;
      transition: all var(--t);
    }
    .hero-breadcrumb:hover { background: rgba(51, 133, 255, 0.25); color: #fff; transform: translateY(-2px); }
    .hero-banner h1 {
      font-size: clamp(2.5rem, 5vw, 3.8rem); font-weight: 800; color: #fff; 
      letter-spacing: -.02em; margin-bottom: 16px; text-shadow: 0 4px 20px rgba(0,0,0,0.3);
    }
    .hero-banner p {
      font-size: 1.15rem; color: rgba(255,255,255,.75); line-height: 1.7; margin-bottom: 0;
    }

    /* ========================================================================== */
    /* FILTER TABS                                                                */
    /* ========================================================================== */
    .filter-tabs {
      display: flex; flex-wrap: wrap; gap: 10px; justify-content: center;
      margin-top: -30px; position: relative; z-index: 10; margin-bottom: 40px;
    }
    .filter-tab {
      padding: 12px 24px; border-radius: 50px; background: #fff; 
      border: 1px solid var(--bdr); font-weight: 700; font-size: .9rem;
      color: var(--text-m); cursor: pointer; transition: all var(--t);
      box-shadow: var(--sh-xs);
    }
    .filter-tab:hover { border-color: var(--primary-l); color: var(--primary); transform: translateY(-2px); box-shadow: var(--sh-sm); }
    .filter-tab.active { 
      background: var(--primary); color: #fff; border-color: var(--primary); 
      box-shadow: 0 6px 16px rgba(0,102,255,0.25); transform: translateY(-2px);
    }
    @media (max-width: 768px) {
      .filter-tabs { margin-top: -20px; gap: 8px; }
      .filter-tab { padding: 10px 18px; font-size: .85rem; }
    }

    /* ========================================================================== */
    /* FACULTY CARDS                                                              */
    /* ========================================================================== */
    .fac-grid {
      display: grid;
      grid-template-columns: repeat(4, 1fr);
      gap: 24px;
      margin-bottom: 40px;
    }
    @media(max-width:1200px) { .fac-grid { grid-template-columns: repeat(3, 1fr); } }
    @media(max-width:900px) { .fac-grid { grid-template-columns: repeat(2, 1fr); } }
    @media(max-width:560px) { .fac-grid { grid-template-columns: 1fr; } }

    .fac-card-wrap {
      animation: fadeInSlideUp 0.4s ease-out forwards;
      opacity: 0;
    }
    @keyframes fadeInSlideUp {
      from { opacity: 0; transform: translateY(20px); }
      to { opacity: 1; transform: translateY(0); }
    }

    .fac-card {
      background: #fff;
      border-radius: 16px;
      overflow: hidden;
      border: 1px solid rgba(0,0,0,0.05);
      box-shadow: var(--sh-sm);
      transition: transform 0.3s cubic-bezier(0.175, 0.885, 0.32, 1.275), box-shadow 0.3s ease;
      cursor: pointer;
      display: flex;
      flex-direction: column;
      text-align: center;
      height: 100%;
    }
    .fac-card:hover {
      transform: translateY(-8px);
      box-shadow: 0 16px 36px rgba(0,0,0,0.08);
      border-color: rgba(51,133,255,0.15);
    }

    .fac-top {
      height: 100px;
      background: linear-gradient(135deg, var(--digital-blue-100), var(--digital-blue-50));
      position: relative;
    }
    .fac-avatar-wrap {
      margin-top: -50px;
      margin-bottom: 16px;
      display: flex;
      justify-content: center;
      position: relative;
      z-index: 2;
    }
    .fac-avatar {
      width: 100px; height: 100px;
      border-radius: 50%;
      border: 4px solid #fff;
      background-color: #fff;
      object-fit: cover;
      box-shadow: var(--sh-sm);
      display: flex; align-items: center; justify-content: center;
      font-size: 2.2rem; font-weight: 800; color: var(--primary);
      transition: transform var(--t);
    }
    .fac-card:hover .fac-avatar { transform: scale(1.05); border-color: var(--primary-l); }

    .fac-body {
      padding: 0 24px 24px;
      display: flex;
      flex-direction: column;
      flex: 1;
    }
    .fac-name {
      font-family: 'DM Sans', sans-serif;
      font-size: 1.2rem;
      font-weight: 800;
      color: var(--primary-d);
      margin-bottom: 4px;
    }
    .fac-desg {
      font-size: .8rem;
      font-weight: 700;
      color: var(--text-m);
      text-transform: uppercase;
      letter-spacing: .05em;
      margin-bottom: 16px;
    }
    .fac-dept-badge {
      align-self: center;
      background: var(--sur-2);
      color: var(--primary);
      font-size: .75rem;
      font-weight: 800;
      padding: 4px 14px;
      border-radius: 50px;
      border: 1px solid var(--bdr);
      margin-bottom: auto;
    }
    .fac-action {
      margin-top: 20px;
      font-size: 0.85rem;
      color: var(--primary);
      font-weight: 700;
      border-top: 1px solid var(--bdr-s);
      padding-top: 16px;
      transition: color var(--t);
    }
    .fac-card:hover .fac-action { color: var(--primary-2); }

    /* Load More Section */
    .load-more-wrap { text-align: center; margin-top: 20px; }
    .load-count { font-size: .9rem; color: var(--text-m); font-weight: 500; margin-top: 12px; display: block; }

    /* ========================================================================== */
    /* LOADING / ERROR STATES                                                     */
    /* ========================================================================== */
    .fac-loader {
      display: flex; flex-direction: column; align-items: center; justify-content: center;
      padding: 80px 20px; gap: 20px; width: 100%; grid-column: 1 / -1;
    }
    .fac-loader-spinner {
      width: 52px; height: 52px; border-radius: 50%;
      border: 4px solid var(--primary-l);
      border-top-color: var(--primary);
      animation: spin 0.8s linear infinite;
    }
    @keyframes spin { to { transform: rotate(360deg); } }
    .fac-loader p { margin: 0; color: var(--text-m); font-weight: 600; font-size: 1rem; }

    .fac-error {
      grid-column: 1 / -1;
      text-align: center; padding: 60px 20px;
      background: #fff; border-radius: 16px; border: 1px solid rgba(239,68,68,0.2);
    }
    .fac-error i { font-size: 2.5rem; color: var(--error); margin-bottom: 12px; display: block; }
    .fac-error h4 { color: var(--primary-d); font-weight: 800; margin-bottom: 8px; }
    .fac-error p { color: var(--text-m); margin: 0; }

    .fac-empty {
      grid-column: 1 / -1;
      text-align: center; padding: 60px 20px;
      background: #fff; border-radius: 16px; border: 1px solid var(--bdr);
    }
    .fac-empty i { font-size: 2.5rem; color: var(--text-m); margin-bottom: 12px; display: block; }
    .fac-empty h4 { color: var(--primary-d); font-weight: 800; margin-bottom: 8px; }
    .fac-empty p { color: var(--text-m); margin: 0; }

    /* ========================================================================== */
    /* SPLIT-LAYOUT MODAL                                                         */
    /* ========================================================================== */
    .fac-modal-overlay {
      display: none;
      position: fixed; inset: 0;
      background: rgba(0,14,36,0.65);
      z-index: 10000;
      align-items: center; justify-content: center;
      padding: 20px;
      backdrop-filter: blur(6px);
      -webkit-backdrop-filter: blur(6px);
    }
    .fac-modal-overlay.open { display: flex; }

    .fac-modal {
      width: 860px; max-width: 100%;
      background: #fff;
      border-radius: 24px;
      overflow: hidden;
      box-shadow: 0 24px 60px rgba(0,0,0,0.2);
      animation: modalPop 0.3s cubic-bezier(0.175, 0.885, 0.32, 1.275);
      display: flex;
      flex-direction: row;
      position: relative;
    }
    @keyframes modalPop {
      from { transform: scale(0.92); opacity: 0; }
      to { transform: scale(1); opacity: 1; }
    }

    .fac-m-top {
      width: 40%;
      position: relative;
      display: flex; align-items: center; justify-content: center;
      background: linear-gradient(135deg, var(--digital-blue-100), var(--digital-blue-50));
      border-right: 1px solid var(--bdr-s);
      padding: 40px;
    }
    .fac-m-top-avatar {
      width: 180px; height: 180px; border-radius: 50%;
      background: #fff; border: 6px solid #fff; box-shadow: var(--sh-md);
      display: flex; align-items: center; justify-content: center;
      font-size: 4rem; font-weight: 800; color: var(--primary);
      object-fit: cover;
    }

    .fac-m-body { 
      width: 60%;
      padding: 48px 40px; 
      background: #fff; 
      overflow-y: auto;
      max-height: 85vh;
      position: relative;
    }

    .fac-m-close {
      position: absolute; top: 20px; right: 20px;
      width: 36px; height: 36px; border-radius: 50%;
      background: var(--sur-2); color: var(--text-s); 
      border: 1px solid var(--bdr);
      display: flex; align-items: center; justify-content: center;
      cursor: pointer; font-size: 1.1rem; z-index: 10;
      transition: all 0.2s;
    }
    .fac-m-close:hover { background: var(--error); color: #fff; border-color: var(--error); transform: rotate(90deg); }

    .fac-m-name {
      font-size: 1.8rem; font-weight: 800; color: var(--primary-d);
      margin: 0 0 6px 0; line-height: 1.2; font-family: 'DM Sans', sans-serif;
    }
    .fac-m-desg {
      font-size: 0.9rem; font-weight: 700; color: var(--text-m);
      text-transform: uppercase; letter-spacing: 0.05em; margin-bottom: 16px;
    }
    .fac-m-dept {
      display: inline-block; background: var(--primary-xl); color: var(--primary);
      padding: 6px 16px; border-radius: 50px; font-size: 0.8rem; font-weight: 800;
      border: 1px solid var(--primary-l); margin-bottom: 32px;
    }

    .fac-m-list { list-style: none; padding: 0; margin: 0; }
    .fac-m-list li {
      display: flex; align-items: center; gap: 16px;
      padding: 16px 0; border-bottom: 1px solid var(--bdr-s);
    }
    .fac-m-list li:last-child { border-bottom: none; padding-bottom: 0; }

    .fac-m-icon {
      width: 44px; height: 44px; border-radius: 12px;
      background: var(--primary-xl); color: var(--primary);
      display: flex; align-items: center; justify-content: center;
      font-size: 1.1rem; flex-shrink: 0;
    }
    .fac-m-info { display: flex; flex-direction: column; gap: 2px; min-width: 0; }
    .fac-m-label { font-size: 0.72rem; text-transform: uppercase; letter-spacing: 0.06em; color: var(--text-m); font-weight: 700; }
    .fac-m-val { font-size: 0.95rem; color: var(--text); font-weight: 600; word-break: break-word; }

    @media(max-width: 720px) {
      .fac-modal { flex-direction: column; max-height: 90vh; overflow-y: auto; }
      .fac-m-top { width: 100%; padding: 32px 20px 24px; }
      .fac-m-body { width: 100%; padding: 28px 20px; max-height: none; }
      .fac-m-top-avatar { width: 130px; height: 130px; font-size: 3rem; }
    }

